class Command(BaseCommand):
    help = 'Popula o banco com as fases da Fantástica Fábrica do Linux.'

    def handle(self, *args, **options):
        created = 0
        updated = 0
        for data in MISSIONS:
            obj, was_created = Mission.objects.update_or_create(
                phase=data['phase'],
                order=data['order'],
                defaults=data,
            )
            if was_created:
                created += 1
            else:
                updated += 1
        self.stdout.write(self.style.SUCCESS(
            f'Missões carregadas. Criadas: {created}. Atualizadas: {updated}. Total: {Mission.objects.count()}'
        ))
